#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long C = 3*X - 2*Y;
        printf("%lld %lld %lld\n", Y, Y, C);
    }
    return 0;
}

